ALTER TABLE `manufacturing_ecm`.`customer`.`account_contact_role` ADD CONSTRAINT `fk_customer_account_contact_role_sales_area_assignment_id` FOREIGN KEY (`sales_area_assignment_id`) REFERENCES `manufacturing_ecm`.`customer`.`sales_area_assignment`(`sales_area_assignment_id`);

